<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>2048</title>
<style>
  body {
    margin: 0;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    background: #1a1a2e;
    color: #eee;
    font-family: "Segoe UI", Arial, sans-serif;
  }
  h1 { margin: 0 0 12px; letter-spacing: 2px; }
  .hud {
    display: flex;
    align-items: center;
    gap: 16px;
    margin-bottom: 16px;
  }
  .score-box {
    background: #16213e;
    padding: 8px 18px;
    border-radius: 8px;
    text-align: center;
  }
  .score-box .label { font-size: 12px; color: #9aa; text-transform: uppercase; }
  #score { font-size: 24px; font-weight: bold; }
  #reset {
    background: #e94560;
    color: #fff;
    border: none;
    padding: 10px 20px;
    border-radius: 8px;
    font-size: 16px;
    cursor: pointer;
  }
  #reset:hover { background: #ff5c77; }
  #board {
    display: grid;
    grid-template-columns: repeat(4, 90px);
    grid-template-rows: repeat(4, 90px);
    gap: 10px;
    background: #16213e;
    padding: 10px;
    border-radius: 12px;
  }
  .cell {
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: 8px;
    font-size: 32px;
    font-weight: bold;
    background: #0f3460;
    color: #eee;
  }
  .cell.empty { background: #22335c; }
  .cell.v2    { background: #3a506b; }
  .cell.v4    { background: #4a6fa5; }
  .cell.v8    { background: #f2a154; color: #222; }
  .cell.v16   { background: #f07b3f; color: #fff; }
  .cell.v32   { background: #ea5455; color: #fff; }
  .cell.v64   { background: #e94560; color: #fff; }
  .cell.v128  { background: #ffd460; color: #222; font-size: 28px; }
  .cell.v256  { background: #ffc93c; color: #222; font-size: 28px; }
  .cell.v512  { background: #ffb400; color: #222; font-size: 28px; }
  .cell.v1024 { background: #9b5de5; color: #fff; font-size: 24px; }
  .cell.v2048 { background: #00bbf9; color: #fff; font-size: 24px; }
  .hint { margin-top: 14px; color: #778; font-size: 13px; }
</style>
</head>
<body>
  <h1>2048</h1>
  <div class="hud">
    <div class="score-box">
      <div class="label">Score</div>
      <div id="score">0</div>
    </div>
    <button id="reset">New Game</button>
  </div>
  <div id="board"></div>
  <div class="hint">Use arrow keys to move tiles.</div>

<script>
(function () {
  const SIZE = 4;
  let grid = [];
  let scoreVal = 0;

  const boardEl = document.getElementById('board');
  const scoreEl = document.getElementById('score');

  function emptyGrid() {
    return Array.from({ length: SIZE }, () => Array(SIZE).fill(0));
  }

  function render() {
    boardEl.innerHTML = '';
    for (let r = 0; r < SIZE; r++) {
      for (let c = 0; c < SIZE; c++) {
        const v = grid[r][c];
        const cell = document.createElement('div');
        cell.className = 'cell ' + (v === 0 ? 'empty' : 'v' + v);
        cell.textContent = v === 0 ? '' : String(v);
        boardEl.appendChild(cell);
      }
    }
    scoreEl.textContent = String(scoreVal);
  }

  function emptyCells() {
    const out = [];
    for (let r = 0; r < SIZE; r++)
      for (let c = 0; c < SIZE; c++)
        if (grid[r][c] === 0) out.push([r, c]);
    return out;
  }

  function spawn() {
    const cells = emptyCells();
    if (cells.length === 0) return;
    const [r, c] = cells[Math.floor(Math.random() * cells.length)];
    grid[r][c] = Math.random() < 0.9 ? 2 : 4;
  }

  // Slide+merge one row toward the left. Each tile merges at most once.
  function slideRow(row) {
    const tiles = row.filter(v => v !== 0);
    const out = [];
    for (let i = 0; i < tiles.length; i++) {
      if (i + 1 < tiles.length && tiles[i] === tiles[i + 1]) {
        const merged = tiles[i] * 2;
        out.push(merged);
        scoreVal += merged;
        i++; // skip the tile we merged with
      } else {
        out.push(tiles[i]);
      }
    }
    while (out.length < SIZE) out.push(0);
    return out;
  }

  function getLine(dir, i) {
    const line = [];
    for (let j = 0; j < SIZE; j++) {
      if (dir === 'left') line.push(grid[i][j]);
      else if (dir === 'right') line.push(grid[i][SIZE - 1 - j]);
      else if (dir === 'up') line.push(grid[j][i]);
      else line.push(grid[SIZE - 1 - j][i]); // down
    }
    return line;
  }

  function setLine(dir, i, line) {
    for (let j = 0; j < SIZE; j++) {
      if (dir === 'left') grid[i][j] = line[j];
      else if (dir === 'right') grid[i][SIZE - 1 - j] = line[j];
      else if (dir === 'up') grid[j][i] = line[j];
      else grid[SIZE - 1 - j][i] = line[j]; // down
    }
  }

  function move(dir) {
    if (!['left', 'right', 'up', 'down'].includes(dir)) return false;
    let changed = false;
    for (let i = 0; i < SIZE; i++) {
      const line = getLine(dir, i);
      const slid = slideRow(line);
      for (let j = 0; j < SIZE; j++) {
        if (line[j] !== slid[j]) changed = true;
      }
      setLine(dir, i, slid);
    }
    if (changed) spawn();
    render();
    return changed;
  }

  function reset() {
    grid = emptyGrid();
    scoreVal = 0;
    spawn();
    spawn();
    render();
  }

  window.game = {
    size: SIZE,
    reset: reset,
    move: move,
    board: () => grid.map(row => row.slice()),
    setBoard: (arr) => {
      grid = arr.map(row => row.map(Number));
      render();
    },
    score: () => scoreVal,
  };

  document.getElementById('reset').addEventListener('click', reset);

  document.addEventListener('keydown', (e) => {
    const map = {
      ArrowLeft: 'left',
      ArrowRight: 'right',
      ArrowUp: 'up',
      ArrowDown: 'down',
    };
    if (map[e.key]) {
      e.preventDefault();
      move(map[e.key]);
    }
  });

  reset();
})();
</script>
</body>
</html>
